from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about an artist (or related entities) into a single,
    fluent English sentence. Handles a variety of predicates and joins multiple
    facts with commas and a final conjunction.
    """
    if not triples:
        return ""

    # Build entity relationships for better sentence construction
    entity_info = {}
    location_hierarchy = {}
    artist_predicates = []
    location_predicates = []

    for t in triples:
        s, p, o = t.subject, t.predicate, t.object

        # Track artist-related information
        if p in {"birthDate", "deathDate", "birthPlace", "deathPlace", "origin",
                 "nationality", "genre", "instrument", "occupation",
                 "associatedBand/associatedMusicalArtist", "recordLabel",
                 "activeYearsStartYear", "activeYearsEndYear", "birthYear", "deathYear",
                 "background", "alternativeName", "professionalField", "training"}:
            artist_predicates.append(t)
        # Track location-related information for building context
        elif p in {"country", "capital", "isPartOf", "governingBody", "leader",
                   "leaderTitle", "language", "officialLanguage", "ethnicGroup",
                   "demonym", "currency", "meaning", "longName", "areaTotal",
                   "populationDensity", "elevationAboveTheSeaLevel", "postalCode",
                   "foundingDate"}:
            location_predicates.append(t)
            # Build location hierarchy
            if p == "country":
                location_hierarchy[o] = location_hierarchy.get(o, []) + [s]
            elif p == "capital":
                location_hierarchy[s] = location_hierarchy.get(s, []) + [f"capital is {o}"]
            elif p == "isPartOf":
                location_hierarchy[s] = location_hierarchy.get(s, []) + [f"part of {o}"]

    phrases = []

    # Process artist predicates first
    for t in artist_predicates:
        s, p, o = t.subject, t.predicate, t.object

        if p == "birthDate":
            phrase = f"{s} was born on {o}"
        elif p == "deathDate":
            phrase = f"{s} died on {o}"
        elif p == "birthPlace":
            # Check if we have country info for this place
            country_info = ""
            for loc_t in location_predicates:
                if loc_t.predicate == "country" and loc_t.subject == o:
                    country_info = f", {loc_t.object}"
                    break
            phrase = f"{s} was born in {o}{country_info}"
        elif p == "deathPlace":
            phrase = f"{s} died in {o}"
        elif p == "origin":
            phrase = f"{s} hails from {o}"
        elif p == "nationality":
            phrase = f"{s} is a {o} national"
        elif p == "genre":
            phrase = f"{s} performs in the {o} genre"
        elif p == "instrument":
            phrase = f"{s} plays {o}"
        elif p == "occupation":
            phrase = f"{s} is a {o}"
        elif p == "associatedBand/associatedMusicalArtist":
            phrase = f"{s} is associated with {o}"
        elif p == "recordLabel":
            phrase = f"{s} is signed to {o}"
        elif p == "activeYearsStartYear":
            phrase = f"{s} began their career in {o}"
        elif p == "activeYearsEndYear":
            phrase = f"{s} concluded their career in {o}"
        elif p == "birthYear":
            phrase = f"{s} was born in {o}"
        elif p == "deathYear":
            phrase = f"{s} died in {o}"
        elif p == "background":
            phrase = f"{s} has a background as a {o}"
        elif p == "alternativeName":
            phrase = f"{s} is also known as {o}"
        elif p == "professionalField":
            phrase = f"{s} works in {o}"
        elif p == "training":
            phrase = f"{s} trained at {o}"
        else:
            phrase = f"{s} {p} {o}"

        phrases.append(phrase)

    # Process location predicates to build context
    for t in location_predicates:
        s, p, o = t.subject, t.predicate, t.object

        if p == "country":
            # Already handled in birthPlace/deathPlace context
            continue
        elif p == "capital":
            phrase = f"the capital of {s} is {o}"
        elif p == "isPartOf":
            phrase = f"{s} is part of {o}"
        elif p == "governingBody":
            phrase = f"{s} is governed by {o}"
        elif p == "leader":
            phrase = f"{s} is led by {o}"
        elif p == "leaderTitle":
            phrase = f"the leader title in {s} is {o}"
        elif p in {"language", "officialLanguage"}:
            phrase = f"{s} uses {o}"
        elif p == "ethnicGroup":
            phrase = f"the main ethnic group in {s} is {o}"
        elif p == "demonym":
            phrase = f"people from {s} are called {o}"
        elif p == "currency":
            phrase = f"{s} uses the {o}"
        elif p == "meaning":
            phrase = f"the name {s} means {o}"
        elif p == "longName":
            phrase = f"the long name of {s} is {o}"
        elif p == "areaTotal":
            phrase = f"{s} has a total area of {o}"
        elif p == "populationDensity":
            phrase = f"{s} has a population density of {o}"
        elif p == "elevationAboveTheSeaLevel":
            phrase = f"{s} is {o} meters above sea level"
        elif p == "postalCode":
            phrase = f"{s} has postal codes {o}"
        elif p == "foundingDate":
            phrase = f"{s} was founded on {o}"
        else:
            phrase = f"{s} {p} {o}"

        phrases.append(phrase)

    # Join phrases into a coherent, complex sentence
    if not phrases:
        return ""
    elif len(phrases) == 1:
        return phrases[0] + "."
    elif len(phrases) == 2:
        return f"{phrases[0]}, and {phrases[1]}."
    else:
        return ", ".join(phrases[:-1]) + ", and " + phrases[-1] + "."

# EVOLVE-BLOCK-END

